e) { if (node) { destroy_(node-&gt;_left); destroy_(node-&gt;_right); delete node; node = nullptr; } } TreeNode*&amp; search_(TreeNode*&amp; node, K key) const { if (!node || key == node-&gt;_pair.first) { return node; } if (key &lt; node-&gt;_pair.first) { return search_(node-&gt;_left, key); } return search_(node-&gt;_right, key); } void insert_(TreeNode*&amp; node, const Pair&amp; pair) { if (!node) { node = new TreeNode(pair); return; } auto key = pair.first; if (key == node-&gt;_pair.first) { node-&gt;_pair = pair; } else if (key &lt; node-&gt;_pair.first) { insert_(node-&gt;_left, pair); } else { insert_(node-&gt;_right, pair); } } TreeNode*&amp; go_to_max_(TreeNode*&amp; node) { while (node-&gt;_right) { node = node-&gt;_right; } return node; } TreeNode*&amp; go_to_min_(TreeNode*&amp; node) { while (node-&gt;_left) { node = node-&gt;_left; } return node; } void delete_(TreeNode*&amp; node, K key) { auto&amp; target = search_(node, key); if (!target) { return; } if (!target-&gt;_left &amp;&amp; !target-&gt;_right) { delete target; target = nullptr; return; } if (!target-&gt;_left) { TreeNode* temp = target-&gt;_right; delete target; target = temp; return; } if (!target-&gt;_right) { TreeNode* temp = target-&gt;_left; delete target; target = temp; return; } auto&amp; max_in_left = go_to_max_(target-&gt;_left); target-&gt;_pair = max_in_left-&gt;_pair; // 1. 常规的递归，把整个左子树当做新的树 // delete_(target-&gt;_left, max_in_left-&gt;_pair.first); // 2. 直接传入 max_in_left 即可 // delete_(max_in_left, max_in_left-&gt;_pair.first); // 3. 实际上不需要递归，因为 max_in_left 是左边最大的值，一定没有右子树 TreeNode* temp = max_in_left-&gt;_left; delete max_in_left; max_in_left = temp; // 我开始时候的代码（有误）： // auto&amp; max_in_left = go_to_max_(node-&gt;_left); // 应该是 // current-&gt;_left current-&gt;_pair = max_in_left-&gt;_pair; delete // (max_in_left); max_in_left = nullptr; // 第三种和我开始时候的逻辑类似 // 但我当时忘了保留 max_in_left 的左子树（如果存在） } static void normal_print_func_(const Pair&amp; pair) { std::cout &lt;&lt; pair.second &lt;&lt; &#34; | &#34;; } void in_order_(TreeNode* node, std::function&lt;void(const Pair&amp;)&gt; func) { if (!node) { return; } in_order_(node-&gt;_left, func); func(node-&gt;_pair); in_order_(node-&gt;_right, func); } public: PairBSTree() : _root(nullptr) {} PairBSTree(const std::vector&lt;Pair&gt;&amp; pairs) : _root(nullptr) { build_(pairs); } PairBSTree(std::vector&lt;Pair&gt;&amp;&amp; pairs) : _root(nullptr) { build_(std::move(pairs)); } ~PairBSTree() { destroy_(_root); } std::optional&lt;V&gt; Search(K key) { auto node = search_(_root, key); if (!node) { return std::nullopt; } return node-&gt;_pair.second; } void Insert(const Pair&amp; pair) { insert_(_root, pair); } void Delete(K key) { delete_(_root, key); } void InOrder(std::function&lt;void(Pair)&gt; func = normal_print_func_) { in_order_(_root, func); } [[nodiscard]] size_t Size() { size_t size = 0; InOrder([&amp;size](std::pair&lt;K, V&gt;) { ++size; }); return size; } [[nodiscard]] V Max() { auto temp = _root; go_to_max_(temp); return temp-&gt;_pair.second; } [[nodiscard]] V Min() { auto temp = _root; go_to_min_(temp); return temp-&gt;_pair.second; } }; int main(void) { std::vector&lt;std::pair&lt;int, std::string&gt;&gt; pairs = { {2, &#34;Bob&#34;}, {9, &#34;Jack&#34;}, {4, &#34;Lucy&#34;}, {23, &#34;Evan&#34;}, {3, &#34;Gorge&#34;}, {12, &#34;Lily&#34;}, {15, &#34;Mono&#34;}, {90, &#34;Rick&#34;}, {14, &#34;Lance&#34;}, {76, &#34;Molly&#34;}, {24, &#34;Stan&#34;}, {11, &#34;Scot&#34;}, {54, &#34;Mint&#34;}, {37, &#34;Biance&#34;}, {35, &#34;Cower&#34;}, {1, &#34;Brick&#34;}, }; PairBSTree tree(pairs); std::cout &lt;&lt; &#34;Name of 9: &#34; &lt;&lt; tree.Search(9).value_or(&#34;nothing&#34;) &lt;&lt; &#39;
&#39;; std::cout &lt;&lt; &#34;Size: &#34; &lt;&lt; tree.Size() &lt;&lt; &#39;
&#39;; // std::cout &lt;&lt; &#34;Min: &#34; &lt;&lt; tree.Min() &lt;&lt; &#39;
&#39;; // std::cout &lt;&lt; &#34;Max: &#34; &lt;&lt; tree.Max() &lt;&lt; &#39;
&#39;; tree.InOrder(); std::cout &lt;&lt; &#39;
&#39;; tree.Delete(15); std::cout &lt;&lt; &#34;Size: &#34; &lt;&lt; tree.Size() &lt;&lt; &#39;
&#39;; tree.InOrder(); std::cout &lt;&lt; &#39;
&#39;; std::vector&lt;std::string&gt; names_in_order; tree.InOrder([&amp;names_in_order](std::pair&lt;int, std::string&gt; pair) { std::cout &lt;&lt; pair.second &lt;&lt; &#34; -- &#34;; names_in_order.push_back(pair.second); }); std::cout &lt;&lt; std::endl; return 0; }
